import{_ as e,c as o,o as t,a as r}from"./app.7b8d607a.js";const b=JSON.parse(`{"title":"Google: A Misrepresented Evil","description":"Don't be evil, sometimes.","frontmatter":{"title":"Google: A Misrepresented Evil","description":"Don't be evil, sometimes.","editLink":true},"headers":[{"level":2,"title":"Humble beginnings","slug":"humble-beginnings"}],"relativePath":"google.md","lastUpdated":1657922291000}`),n={name:"google.md"},a=r('<h1 id="google-a-misrepresented-evil" tabindex="-1">Google: A Misrepresented Evil <a class="header-anchor" href="#google-a-misrepresented-evil" aria-hidden="true">#</a></h1><p><strong>Don&#39;t be evil, sometimes</strong></p><p>Last updated on: 2022-06-06</p><h2 id="humble-beginnings" tabindex="-1">Humble beginnings <a class="header-anchor" href="#humble-beginnings" aria-hidden="true">#</a></h2><p>Google had its <a href="https://about.google/our-story/" target="_blank" rel="noopener noreferrer">humble beginnings</a> in 1995 as a research project by Stanford University students Larry Page, Sergey Brin, and Scott Hassan. While Hassan left before the company was officially founded, the other two remained, and went on to become owners of one of the <a href="https://www.gobankingrates.com/money/business/how-much-is-google-worth/" target="_blank" rel="noopener noreferrer">largest companies</a> in the world.</p><p>Now, the company that started out as a simple search engine controls the daily lives of millions of people around the world, with their <a href="https://sg.oberlo.com/statistics/search-engine-market-share" target="_blank" rel="noopener noreferrer">largest product</a> being Google Search. It&#39;s so popular that &quot;Googling&quot; has become <a href="https://www.merriam-webster.com/dictionary/google" target="_blank" rel="noopener noreferrer">synonymous</a> with searching the web.</p>',6),s=[a];function i(l,h,g,d,p,c){return t(),o("div",null,s)}var _=e(n,[["render",i]]);export{b as __pageData,_ as default};
